SELECT TOP 1 [ARTICLE_ID], SUM(AS.[DAILY_VIEWS]) AS TOTAL_VIEWS 
FROM [ARTICLE_STATISTICS] AS 
WHERE AS.[IsDeleted] = 0 
	AND AS.[STATISTICS_DATE] > DATEADD(DAY, -30,
	GETDATE()) 
GROUP BY AS.[ARTICLE_ID] 
ORDER BY AS.[TOTAL_VIEWS] DESC 